import{_ as e,o as l,c as t,a2 as r}from"./chunks/framework.m9rfQn3T.js";const u=JSON.parse('{"title":"重绘和回流","description":"","frontmatter":{"title":"重绘和回流","date":"2021-06-17T17:19:33.000Z","permalink":"/pages/806eb7f413442/","categories":["面试题","浏览器"],"tags":[null]},"headers":[],"relativePath":"10.面试题/35.浏览器/05.重绘和回流.md","filePath":"10.面试题/35.浏览器/05.重绘和回流.md","lastUpdated":1782538095000}'),i={name:"10.面试题/35.浏览器/05.重绘和回流.md"};function o(n,a,h,s,p,d){return l(),t("div",null,[...a[0]||(a[0]=[r('<p>重绘不一定导致回流，但回流一定发生了重绘</p><h2 id="渲染流程" tabindex="-1">渲染流程 <a class="header-anchor" href="#渲染流程" aria-label="Permalink to &quot;渲染流程&quot;">​</a></h2><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210725205922.png" alt="20210725205922"></p><ul><li>构建 dom 树</li><li>构建渲染树</li><li>布局</li><li>绘制</li><li>渲染合成层</li></ul><p>&lt;!--more--&gt;</p><h2 id="回流-重排" tabindex="-1">回流(重排) <a class="header-anchor" href="#回流-重排" aria-label="Permalink to &quot;回流(重排)&quot;">​</a></h2><h3 id="触发条件" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件" aria-label="Permalink to &quot;触发条件&quot;">​</a></h3><p>简单来说，就是当我们对 DOM 结构的修改引发 DOM 几何尺寸变化的时候，会发生回流的过程</p><ul><li>一个 DOM 元素的几何属性变化，常见的几何属性有 width、height、padding、margin、left、top、border 等等, 这个很好理解</li><li>使 DOM 节点发生增减或者移动</li><li>读写 offset 族、scroll 族和 client 族属性的时候，浏览器为了获取这些值，需要进行回流操作</li><li>调用 window.getComputedStyle 方法</li></ul><h2 id="回流过程" tabindex="-1">回流过程 <a class="header-anchor" href="#回流过程" aria-label="Permalink to &quot;回流过程&quot;">​</a></h2><p>依照上面的渲染流水线，触发回流的时候，如果 DOM 结构发生改变，则重新渲染 DOM 树，然后将后面的流程(包括主线程之外的任务)全部走一遍</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210725210427.png" alt="20210725210427"></p><p>相当于将解析和合成的过程重新又走了一篇，开销是非常大的</p><h2 id="重绘" tabindex="-1">重绘 <a class="header-anchor" href="#重绘" aria-label="Permalink to &quot;重绘&quot;">​</a></h2><h3 id="触发条件-1" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件-1" aria-label="Permalink to &quot;触发条件&quot;">​</a></h3><p>当 DOM 的修改导致了样式的变化，并且没有影响几何属性的时候，会导致重绘(repaint)</p><h3 id="重回过程" tabindex="-1">重回过程 <a class="header-anchor" href="#重回过程" aria-label="Permalink to &quot;重回过程&quot;">​</a></h3><p>由于没有导致 DOM 几何属性的变化，因此元素的位置信息不需要更新，从而省去布局的过程。流程如下：</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210725210534.png" alt="20210725210534"></p><p>跳过了生成布局树和建图层树的阶段，直接生成绘制列表，然后继续进行分块、生成位图等后面一系列操作。</p><h2 id="合成" tabindex="-1">合成 <a class="header-anchor" href="#合成" aria-label="Permalink to &quot;合成&quot;">​</a></h2><p>还有一种情况，是直接合成。比如利用 CSS3 的 transform、opacity、filter 这些属性就可以实现合成的效果，也就是大家常说的 GPU 加速</p><h3 id="gpu-加速原因" tabindex="-1">GPU 加速原因 <a class="header-anchor" href="#gpu-加速原因" aria-label="Permalink to &quot;GPU 加速原因&quot;">​</a></h3><p>在合成的情况下，会直接跳过布局和绘制流程，直接进入非主线程处理的部分，即直接交给合成线程处理。交给它处理有两大好处:</p><ol><li><p>能够充分发挥 GPU 的优势。合成线程生成位图的过程中会调用线程池，并在其中使用 GPU 进行加速生成，而 GPU 是擅长处理位图数据的。</p></li><li><p>没有占用主线程的资源，即使主线程卡住了，效果依然能够流畅地展示。</p></li></ol><h2 id="警惕" tabindex="-1">警惕 <a class="header-anchor" href="#警惕" aria-label="Permalink to &quot;警惕&quot;">​</a></h2><ul><li>避免频繁使用 style，而是采用修改 class 的方式</li><li>使用 createDocumentFragment 进行批量的 DOM 操作</li><li>对于 resize、scroll 等进行防抖/节流处理</li><li>添加 will-change: tranform ，让渲染引擎为其单独实现一个图层，当这些变换发生时，仅仅只是利用合成线程去处理这些变换，而不牵扯到主线程，大大提高渲染效率。当然这个变化不限于 tranform, 任何可以实现合成效果的 CSS 属性都能用 will-change 来声明</li></ul><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://juejin.cn/post/6844903966573068301" target="_blank" rel="noreferrer">https://juejin.cn/post/6844903966573068301</a></li><li><a href="https://sanyuan0704.top/my_blog/blogs/browser/browser-render/004.html" target="_blank" rel="noreferrer">https://sanyuan0704.top/my_blog/blogs/browser/browser-render/004.html</a></li></ul>',29)])])}const m=e(i,[["render",o]]);export{u as __pageData,m as default};
